import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PollenLevel {
  level: string;
  count: number;
  severity: string;
}

interface WeeklyPollenTrend {
  day: string;
  tree: number;
  grass: number;
  weed: number;
}

interface PollenData {
  location: string;
  currentPollenLevel: {
    tree: PollenLevel;
    grass: PollenLevel;
    weed: PollenLevel;
  };
  weeklyPollenTrend: WeeklyPollenTrend[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const pollenData = response.data as PollenData;
  const metaData = response.meta as MetaData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 500,
        bgcolor: '#FFFFFF',
        borderRadius: 2,
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor, fontWeight: 600 }}>
              Pollen Levels in {pollenData.location}
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
              {Object.entries(pollenData.currentPollenLevel).map(([type, level]) => (
                <Chip
                  key={type}
                  label={`${type.charAt(0).toUpperCase() + type.slice(1)}: ${level.level}`}
                  sx={{
                    bgcolor: metaData.accentColor,
                    color: '#FFFFFF',
                    fontSize: '12px',
                    fontWeight: 500,
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              series={[
                {
                  data: pollenData.weeklyPollenTrend.map((day) => day.tree),
                  label: 'Tree',
                  color: '#FF5722',
                },
                {
                  data: pollenData.weeklyPollenTrend.map((day) => day.grass),
                  label: 'Grass',
                  color: '#FFC107',
                },
                {
                  data: pollenData.weeklyPollenTrend.map((day) => day.weed),
                  label: 'Weed',
                  color: '#4CAF50',
                },
              ]}
              xAxis={[
                {
                  data: pollenData.weeklyPollenTrend.map((day) => day.day),
                  scaleType: 'band',
                  tickLabelStyle: { fontSize: 10, fill: '#6B7280' },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
